namespace sv_cc137fdcee85455cb080c93874785761.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

.settings-sidebar {
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    height: 100%;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.nav-link {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.nav-link.active {
    background-color: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

.section-icon {
    font-size: 1.1rem;
}

@using sv_cc137fdcee85455cb080c93874785761.Services
@inject ISettingsService SettingsService

@if (isLoading)
{
    <div class="text-center p-4">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="section-header">
        <h3>Profile</h3>
        <p class="text-muted">Manage your personal information</p>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <div class="avatar-section mb-4">
        <div class="avatar-preview">
            @if (!string.IsNullOrWhiteSpace(editAvatarUrl))
            {
                <img src="@editAvatarUrl" alt="Avatar" class="avatar-image" />
            }
            else
            {
                <div class="avatar-placeholder">No Avatar</div>
            }
        </div>
        <div class="avatar-url flex-grow-1">
            <label class="form-label fw-semibold">Avatar URL</label>
            <input type="url" class="form-control" @bind="editAvatarUrl" placeholder="https://example.com/avatar.png" />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Display Name</label>
        <input type="text" class="form-control" @bind="editDisplayName" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Email</label>
        <input type="email" class="form-control" @bind="editEmail" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Bio</label>
        <textarea class="form-control" rows="4" @bind="editBio" placeholder="Tell us about yourself..."></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@isSaving">
            @if (isSaving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges">Discard Changes</button>
    </div>
}

@code {
    private UserProfile? savedProfile;
    private string editDisplayName = "";
    private string editEmail = "";
    private string editAvatarUrl = "";
    private string editBio = "";
    private bool isLoading = true;
    private bool isSaving;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        savedProfile = await SettingsService.GetProfileAsync();
        PopulateForm(savedProfile);
        isLoading = false;
    }

    private void PopulateForm(UserProfile profile)
    {
        editDisplayName = profile.DisplayName;
        editEmail = profile.Email;
        editAvatarUrl = profile.AvatarUrl;
        editBio = profile.Bio;
    }

    private async Task SaveChanges()
    {
        isSaving = true;
        var updated = new UserProfile(editDisplayName, editEmail, editAvatarUrl, editBio);
        await SettingsService.SaveProfileAsync(updated);
        savedProfile = updated;
        statusMessage = "Profile saved successfully!";
        isSaving = false;
    }

    private void DiscardChanges()
    {
        if (savedProfile is not null)
        {
            PopulateForm(savedProfile);
        }
        statusMessage = null;
    }
}

.section-header h3 {
    margin-bottom: 0.25rem;
}

.section-header {
    margin-bottom: 1.5rem;
}

.avatar-section {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-preview {
    flex-shrink: 0;
}

.avatar-image {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.avatar-placeholder {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.85rem;
    border: 3px solid #dee2e6;
}

@using sv_cc137fdcee85455cb080c93874785761.Services
@inject ISettingsService SettingsService

@if (isLoading)
{
    <div class="text-center p-4">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="section-header">
        <h3>Notifications</h3>
        <p class="text-muted">Configure how you receive notifications</p>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <div class="card mb-3">
        <div class="card-header fw-semibold">Notification Channels</div>
        <div class="card-body">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                    <small class="d-block text-muted">Receive updates via email</small>
                </label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                    <small class="d-block text-muted">Receive browser push notifications</small>
                </label>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                    <small class="d-block text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header fw-semibold">Muted Channels</div>
        <div class="card-body">
            @if (allChannels.Count == 0)
            {
                <p class="text-muted mb-0">No channels available.</p>
            }
            else
            {
                <p class="text-muted small mb-3">Check a channel to mute it. Muted channels will not send notifications.</p>
                @foreach (var channel in allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SavePreferences" disabled="@isSaving">
        @if (isSaving)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Save Preferences
    </button>
}

@code {
    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private List<string> allChannels = new();
    private bool isLoading = true;
    private bool isSaving;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        emailNotifications = prefs.EmailNotifications;
        pushNotifications = prefs.PushNotifications;
        weeklyDigest = prefs.WeeklyDigest;
        allChannels = new List<string>(prefs.MutedChannels);
        mutedChannels = new HashSet<string>(prefs.MutedChannels);
        isLoading = false;
    }

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        isSaving = true;
        var prefs = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        statusMessage = "Notification preferences saved!";
        isSaving = false;
    }
}

@using sv_cc137fdcee85455cb080c93874785761.Services
@inject ISettingsService SettingsService

@if (isLoading)
{
    <div class="text-center p-4">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="section-header">
        <h3>Security</h3>
        <p class="text-muted">Manage your account security settings</p>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @statusAlertClass alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <!-- Change Password -->
    <div class="card mb-3">
        <button class="card-header d-flex justify-content-between align-items-center border-0 bg-transparent w-100 text-start fw-semibold"
                @onclick="() => passwordPanelOpen = !passwordPanelOpen">
            <span>Change Password</span>
            <span>@(passwordPanelOpen ? "▲" : "▼")</span>
        </button>
        @if (passwordPanelOpen)
        {
            <div class="card-body pt-0">
                @if (lastPasswordChange.HasValue)
                {
                    <p class="text-muted small">Last changed: @lastPasswordChange.Value.ToString("MMMM d, yyyy")</p>
                }
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="confirmPassword" />
                </div>
                @if (!string.IsNullOrEmpty(passwordError))
                {
                    <div class="text-danger mb-2">@passwordError</div>
                }
                <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@isChangingPassword">
                    @if (isChangingPassword)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Update Password
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1 fw-semibold">Two-Factor Authentication</h6>
                <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" id="twoFactor" @bind="twoFactorEnabled" />
                <label class="form-check-label visually-hidden" for="twoFactor">Toggle two-factor authentication</label>
            </div>
        </div>
    </div>

    <!-- Active Sessions -->
    <div class="card mb-3">
        <div class="card-header fw-semibold">Active Sessions</div>
        <div class="card-body p-0">
            @if (sessions.Count == 0)
            {
                <p class="text-muted p-3 mb-0">No active sessions.</p>
            }
            else
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @for (var i = 0; i < sessions.Count; i++)
                            {
                                var session = sessions[i];
                                var isCurrentSession = i == 0;
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (isCurrentSession)
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => ConfirmRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
        </div>
    </div>

    @if (sessionToRevoke is not null)
    {
        <div class="modal-backdrop fade show"></div>
        <div class="modal d-block" tabindex="-1" role="dialog">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on
                            <strong>@sessionToRevoke.Device</strong> from
                            <strong>@sessionToRevoke.Location</strong>?
                        </p>
                        <p class="text-muted small mb-0">This will sign out the device immediately.</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="RevokeSession" disabled="@isRevoking">
                            @if (isRevoking)
                            {
                                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                            }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool isLoading = true;
    private bool passwordPanelOpen;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? passwordError;
    private bool isChangingPassword;
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();
    private ActiveSession? sessionToRevoke;
    private bool isRevoking;
    private string? statusMessage;
    private string statusAlertClass = "alert-success";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = new List<ActiveSession>(settings.Sessions);
        isLoading = false;
    }

    private async Task UpdatePassword()
    {
        passwordError = null;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            passwordError = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            passwordError = "New passwords do not match.";
            return;
        }

        isChangingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            statusMessage = "Password updated successfully!";
            statusAlertClass = "alert-success";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
            passwordPanelOpen = false;
        }
        catch (Exception ex)
        {
            passwordError = ex.Message;
        }
        finally
        {
            isChangingPassword = false;
        }
    }

    private void ConfirmRevoke(ActiveSession session) => sessionToRevoke = session;
    private void CancelRevoke() => sessionToRevoke = null;

    private async Task RevokeSession()
    {
        if (sessionToRevoke is null) return;

        isRevoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
            sessions.Remove(sessionToRevoke);
            statusMessage = $"Session on {sessionToRevoke.Device} has been revoked.";
            statusAlertClass = "alert-success";
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to revoke session: {ex.Message}";
            statusAlertClass = "alert-danger";
        }
        finally
        {
            sessionToRevoke = null;
            isRevoking = false;
        }
    }
}

