    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1 fw-semibold">Two-Factor Authentication</h6>
                <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" id="twoFactor" @bind="twoFactorEnabled" />
                <label class="form-check-label visually-hidden" for="twoFactor">Toggle two-factor authentication</label>
            </div>
        </div>
    </div>

    <!-- Active Sessions -->
    <div class="card mb-3">
        <div class="card-header fw-semibold">Active Sessions</div>
        <div class="card-body p-0">
            @if (sessions.Count == 0)
            {
                <p class="text-muted p-3 mb-0">No active sessions.</p>
            }
            else
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @for (var i = 0; i < sessions.Count; i++)
                            {
                                var session = sessions[i];
                                var isCurrentSession = i == 0;
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (isCurrentSession)
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => ConfirmRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
        </div>
    </div>

    @if (sessionToRevoke is not null)
    {
        <div class="modal-backdrop fade show"></div>
        <div class="modal d-block" tabindex="-1" role="dialog">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on
                            <strong>@sessionToRevoke.Device</strong> from
                            <strong>@sessionToRevoke.Location</strong>?
                        </p>
                        <p class="text-muted small mb-0">This will sign out the device immediately.</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="RevokeSession" disabled="@isRevoking">
                            @if (isRevoking)
                            {
                                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                            }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool isLoading = true;
    private bool passwordPanelOpen;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? passwordError;
    private bool isChangingPassword;
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();
    private ActiveSession? sessionToRevoke;
    private bool isRevoking;
    private string? statusMessage;
    private string statusAlertClass = "alert-success";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = new List<ActiveSession>(settings.Sessions);
        isLoading = false;
    }

    private async Task UpdatePassword()
    {
        passwordError = null;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            passwordError = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            passwordError = "New passwords do not match.";
            return;
        }

        isChangingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            statusMessage = "Password updated successfully!";
            statusAlertClass = "alert-success";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
            passwordPanelOpen = false;
        }
        catch (Exception ex)
        {
            passwordError = ex.Message;
        }
        finally
        {
            isChangingPassword = false;
        }
    }

    private void ConfirmRevoke(ActiveSession session) => sessionToRevoke = session;
    private void CancelRevoke() => sessionToRevoke = null;

    private async Task RevokeSession()
    {
        if (sessionToRevoke is null) return;

        isRevoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
            sessions.Remove(sessionToRevoke);
            statusMessage = $"Session on {sessionToRevoke.Device} has been revoked.";
            statusAlertClass = "alert-success";
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to revoke session: {ex.Message}";
            statusAlertClass = "alert-danger";
        }
        finally
        {
            sessionToRevoke = null;
            isRevoking = false;
        }
    }
}

