        <p class="text-muted">Manage your account security settings</p>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @statusAlertClass alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <!-- Change Password -->
    <div class="card mb-3">
        <button class="card-header d-flex justify-content-between align-items-center border-0 bg-transparent w-100 text-start fw-semibold"
                @onclick="() => passwordPanelOpen = !passwordPanelOpen">
            <span>Change Password</span>
            <span>@(passwordPanelOpen ? "▲" : "▼")</span>
        </button>
        @if (passwordPanelOpen)
        {
            <div class="card-body pt-0">
                @if (lastPasswordChange.HasValue)
                {
                    <p class="text-muted small">Last changed: @lastPasswordChange.Value.ToString("MMMM d, yyyy")</p>
                }
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="confirmPassword" />
                </div>
                @if (!string.IsNullOrEmpty(passwordError))
                {
                    <div class="text-danger mb-2">@passwordError</div>
                }
                <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@isChangingPassword">
                    @if (isChangingPassword)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Update Password
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1 fw-semibold">Two-Factor Authentication</h6>
                <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" id="twoFactor" @bind="twoFactorEnabled" />
                <label class="form-check-label visually-hidden" for="twoFactor">Toggle two-factor authentication</label>
            </div>
        </div>
    </div>

    <!-- Active Sessions -->
    <div class="card mb-3">
        <div class="card-header fw-semibold">Active Sessions</div>
        <div class="card-body p-0">
            @if (sessions.Count == 0)
            {
                <p class="text-muted p-3 mb-0">No active sessions.</p>
            }
            else
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @for (var i = 0; i < sessions.Count; i++)
                            {
                                var session = sessions[i];
                                var isCurrentSession = i == 0;
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (isCurrentSession)
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => ConfirmRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
        </div>
    </div>

    @if (sessionToRevoke is not null)
    {
        <div class="modal-backdrop fade show"></div>
        <div class="modal d-block" tabindex="-1" role="dialog">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on
                            <strong>@sessionToRevoke.Device</strong> from
                            <strong>@sessionToRevoke.Location</strong>?
                        </p>
                        <p class="text-muted small mb-0">This will sign out the device immediately.</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="RevokeSession" disabled="@isRevoking">
                            @if (isRevoking)
                            {
                                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                            }
                            Revoke
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool isLoading = true;
    private bool passwordPanelOpen;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? passwordError;
    private bool isChangingPassword;
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();
    private ActiveSession? sessionToRevoke;
    private bool isRevoking;
    private string? statusMessage;
    private string statusAlertClass = "alert-success";

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = new List<ActiveSession>(settings.Sessions);
        isLoading = false;
    }

    private async Task UpdatePassword()
    {
        passwordError = null;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            passwordError = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            passwordError = "New passwords do not match.";
            return;
        }

        isChangingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            statusMessage = "Password updated successfully!";
            statusAlertClass = "alert-success";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
            passwordPanelOpen = false;
        }
        catch (Exception ex)
        {
            passwordError = ex.Message;
        }
        finally
        {
            isChangingPassword = false;
        }
    }

    private void ConfirmRevoke(ActiveSession session) => sessionToRevoke = session;
    private void CancelRevoke() => sessionToRevoke = null;

    private async Task RevokeSession()
    {
        if (sessionToRevoke is null) return;

        isRevoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
            sessions.Remove(sessionToRevoke);
            statusMessage = $"Session on {sessionToRevoke.Device} has been revoked.";
            statusAlertClass = "alert-success";
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to revoke session: {ex.Message}";
            statusAlertClass = "alert-danger";
        }
        finally
        {
            sessionToRevoke = null;
            isRevoking = false;
        }
    }
}
"}

{"path": "/tmp/sv-cc137fdcee85455cb080c93874785761/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@using sv_cc137fdcee85455cb080c93874785761.Services
@inject ISettingsService SettingsService

@if (isLoading)
{
    <div class="text-center p-4">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="section-header">
        <h3>Appearance</h3>
        <p class="text-muted">Customize the look and feel of the application</p>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <!-- Theme -->
    <div class="card mb-3">
        <div class="card-header fw-semibold">Theme</div>
        <div class="card-body d-flex gap-4">
            @foreach (var t in themes)
            {
                var themeValue = t;
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="theme" id="@($"theme-{themeValue}")"
                           checked="@(theme == themeValue)"
                           @onchange="() => theme = themeValue" />
                    <label class="form-check-label" for="@($"theme-{themeValue}")">@themeValue</label>
                </div>
            }
        </div>
    </div>

    <!-- Font Size -->
    <div class="card mb-3">
        <div class="card-header fw-semibold">Font Size</div>
        <div class="card-body d-flex gap-4">
            @foreach (var size in fontSizes)
            {
                var sizeValue = size;
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{sizeValue}")"
                           checked="@(fontSize == sizeValue)"
                           @onchange="() => fontSize = sizeValue" />
                    <label class="form-check-label" for="@($"fs-{sizeValue}")">@sizeValue</label>
                </div>
            }
        </div>
    </div>

    <!-- Language -->
    <div class="card mb-3">
        <div class="card-header fw-semibold">Language</div>
        <div class="card-body">
            <select class="form-select" style="max-width: 300px;" @bind="language">
                @foreach (var lang in languages)
                {
                    <option value="@lang.Code">@lang.Label</option>
                }
            </select>
        </div>
    </div>

    <!-- Compact Mode -->
    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-0 fw-semibold">Compact Mode</h6>
                <small class="text-muted">Reduce spacing and padding throughout the interface</small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" id="compactMode" @bind="compactMode" />
                <label class="form-check-label visually-hidden" for="compactMode">Toggle compact mode</label>
            </div>
        </div>
    </div>

    <!-- Live Preview -->
    <div class="card mb-3">
        <div class="card-header fw-semibold">Preview</div>
        <div class="preview-area @PreviewThemeClass" style="@PreviewStyle">
            <div class="preview-content">
                <h5 class="preview-heading">Sample Heading</h5>
                <p class="preview-text">This is how your content will look with the selected settings.</p>
                <div class="d-flex gap-2 align-items-center">
                    <button class="btn btn-primary btn-sm">Primary Action</button>
                    <button class="btn btn-outline-secondary btn-sm">Secondary</button>
                    <span class="badge bg-info">Badge</span>
                </div>
            </div>
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@isSaving">
        @if (isSaving)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Save
    </button>
}

@code {
    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private bool isLoading = true;
    private bool isSaving;
    private string? statusMessage;

    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly (string Code, string Label)[] languages =
    [
        ("en", "English"),
        ("es", "Español"),
        ("fr", "Français"),
        ("de", "Deutsch"),
        ("ja", "日本語"),
        ("zh", "中文")
    ];

    private string PreviewThemeClass => theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-light"
    };

    private string PreviewStyle
    {
        get
        {
            var fs = fontSize switch
            {
                "Small" => "0.85rem",
                "Large" => "1.15rem",
                _ => "1rem"
            };
            var padding = compactMode ? "0.75rem" : "1.5rem";
            return $"font-size: {fs}; padding: {padding};";
        }
    }

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        theme = settings.Theme;
        fontSize = settings.FontSize;
        language = settings.Language;
        compactMode = settings.CompactMode;
        isLoading = false;
    }

    private async Task SaveAppearance()
    {
        isSaving = true;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(theme, fontSize, language, compactMode));
        statusMessage = "Appearance settings saved!";
        isSaving = false;
    }
}
"}

