@using sv_cc137fdcee85455cb080c93874785761.Services
@inject ISettingsService SettingsService

@if (isLoading)
{
    <div class="text-center p-4">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="section-header">
        <h3>Profile</h3>
        <p class="text-muted">Manage your personal information</p>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <div class="avatar-section mb-4">
        <div class="avatar-preview">
            @if (!string.IsNullOrWhiteSpace(editAvatarUrl))
            {
                <img src="@editAvatarUrl" alt="Avatar" class="avatar-image" />
            }
            else
            {
                <div class="avatar-placeholder">No Avatar</div>
            }
        </div>
        <div class="avatar-url flex-grow-1">
            <label class="form-label fw-semibold">Avatar URL</label>
            <input type="url" class="form-control" @bind="editAvatarUrl" placeholder="https://example.com/avatar.png" />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Display Name</label>
        <input type="text" class="form-control" @bind="editDisplayName" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Email</label>
        <input type="email" class="form-control" @bind="editEmail" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Bio</label>
        <textarea class="form-control" rows="4" @bind="editBio" placeholder="Tell us about yourself..."></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@isSaving">
